**Mistake 2: Incorrect Termination Condition** An incorrect termination condition can cause an infinite loop. Error Example: ```js
let a = 10;
let counter = 0;
let condition = (counter < 3);
while (condition) {
    a = a + 1;
    console.log(a);
    counter = counter + 1;
}
``` * **Issue**: This code may continue indefinitely if the condition doesn't evaluate to false when expected. * **Fix**: Ensure that the condition properly becomes `false` to terminate the loop.

code_playground.code:
// Incorrect: infinite loop (commented out to prevent hanging)
// let counter = 0;
// while (counter < 3) {
//   console.log(counter);
//   // counter never increments!
// }

// Correct: loop terminates properly
let counter = 0;
while (counter < 3) {
  console.log(counter);
  counter = counter + 1;  // condition eventually becomes false
}
console.log("Loop ended");

// Simulating password validation with a fixed input sequence
const inputs = ["wrong1", "wrong2", "correct"];
let inputIndex = 0;

function getUserInput() {
  const val = inputs[inputIndex];
  inputIndex++;
  return val;
}

// Correct: password is updated each iteration
let password = "";
while (password !== "correct") {
  password = getUserInput();
  console.log("Entered:", password);
}
console.log("Access granted!");
